import{c as t,Q as o,j as a,m as r}from"./chunks/framework.CdiUUa3G.js";const u=JSON.parse('{"title":"PRD-014 — Surface Hotspots · progressive-quality landing-site exploration","description":"","frontmatter":{},"headers":[],"relativePath":"prd/PRD-014.md","filePath":"prd/PRD-014.md"}'),i={name:"prd/PRD-014.md"};function s(n,e,l,h,d,c){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="prd-014-—-surface-hotspots-·-progressive-quality-landing-site-exploration" tabindex="-1">PRD-014 — Surface Hotspots · progressive-quality landing-site exploration <a class="header-anchor" href="#prd-014-—-surface-hotspots-·-progressive-quality-landing-site-exploration" aria-label="Permalink to &quot;PRD-014 — Surface Hotspots · progressive-quality landing-site exploration&quot;">​</a></h1><p><em>Orrery · Product Requirements · v0.1 · May 2026</em></p><blockquote><p><strong>Status:</strong> Draft <strong>Depends on:</strong> PRD-006 (Moon Map), PRD-009 (Mars Surface Map), PRD-012 (Spaceflight Fleet) — this PRD layers on top of all three. <strong>Closes into:</strong> RFC-017 → ADR-059 (LOD architecture), ADR-060 (orbital-imagery texture pipeline + provenance), ADR-061 (ground-view skybox + panorama sourcing), ADR-062 (per-mission hand-authored hardware models). <strong>Slice:</strong> v0.7 (post-v0.6 mobile-UX polish). <strong>Screens affected:</strong> <code>/moon</code> (V1 + V2), <code>/mars</code> (V1 + V2), <code>/iss</code> (V3 reach for orbital hardware), <code>/earth</code> (V3 reach for crewed-spacecraft callouts). <strong>Principles:</strong> physics first, attribution is design, mobile-first, share by URL, no compromise on imagery fidelity (this is the headline feature). Why this is a PRD · Today, Apollo 11&#39;s Tranquillity Base is a small dot on a textured Moon sphere. Curiosity at Gale Crater is a small dot on a textured Mars sphere. The user clicks the dot, a panel opens with a photo gallery. The gallery photos are world-class — Aldrin in front of the LM, the Solar Wind Composition foil unfurled, Earth rising over Schmitt&#39;s helmet at Apollo 17, Curiosity&#39;s selfie at Mont Mercou. But the <strong>map view itself never improves</strong>. The user cannot fly down to the landing site, see the lander on the actual regolith, walk around the rover. This PRD defines that capability.</p></blockquote><hr><h2 id="§why" tabindex="-1">§why <a class="header-anchor" href="#§why" aria-label="Permalink to &quot;§why&quot;">​</a></h2><p>Orrery already ships the world&#39;s most carefully-attributed solar-system encyclopedia in the browser. Every photograph carries a provenance row. Every mission has its real flight events. The /science integration explains every term. And yet, when the user clicks <code>Tranquillity Base</code> on the lunar near-side disc, the visual response is identical to clicking any other dot: the dot lights up, a panel opens, the photo gallery loads. The map stays at its 50,000-km wide-angle view forever.</p><p>The data exists to do dramatically more. NASA&#39;s Lunar Reconnaissance Orbiter Camera (LROC) has imaged every Apollo landing site at 0.5 m/pixel — you can see the descent-stage shadow, the discarded gold-foil from the LM, the rover tracks at Apollo 15/16/17, the astronauts&#39; footprint paths. NASA&#39;s Mars Reconnaissance Orbiter HiRISE camera has imaged Curiosity, Perseverance, InSight, Phoenix, every Viking and Soviet lander — at 25 cm/pixel. NASA has panorama datasets from every Apollo EVA, from Curiosity, from Perseverance, in equirectangular form, in the public domain. The 3D shapes of every lander and rover are documented to engineering tolerance.</p><p><strong>None of this surfaces in /moon or /mars today.</strong></p><p>The vision: a user clicks Apollo 11 on the Moon. The camera <strong>descends.</strong> As it descends, the dot doesn&#39;t just enlarge — it morphs through three quality tiers. At wide zoom: a tiny three-leg silhouette (Tier 0, what we have). At medium zoom: a recognisable 3D Apollo LM with descent + ascent stages, four splayed legs, gold foil, ladder, S-band antenna (Tier 1). At close zoom: the camera is hovering 80 m above the actual surface, and the moon texture under the LM has been replaced by a high-resolution circular patch of the real LROC orbital mosaic showing the descent-stage shadow, Buzz&#39;s MESA, the footprint trail (Tier 2). One more click — &quot;Visit&quot; — and the camera transitions to ground level. The user is standing 5 m from the LM. Around them, the actual Aldrin/Armstrong panorama photographs wrap as a skybox. They can look around. Annotations appear: <em>Tranquillity Base · Apollo 11 · July 20, 1969 · Mare Tranquillitatis</em> (Tier 3).</p><p>This is the <strong>moment Orrery becomes irreplaceable.</strong> Not &quot;another solar-system explorer&quot; — <em>the</em> place where you can stand at Tranquillity Base in 14 languages, on a phone, offline, sharing by URL.</p><p>Marko&#39;s framing: <em>&quot;WIRED is a baby compared to what we&#39;ll build here. National Geographic will call us. NASA will hire us.&quot;</em> This PRD codifies the no-compromise promise that gets us there.</p><hr><h2 id="§audiences" tabindex="-1">§audiences <a class="header-anchor" href="#§audiences" aria-label="Permalink to &quot;§audiences&quot;">​</a></h2><p><strong>Primary — curious lay person who has heard of Apollo and Curiosity.</strong> The &quot;I saw something on TV about Mars&quot; visitor. Knows roughly that humans landed on the Moon and rovers are on Mars; has no detailed sense of where, how, or what those sites look like. Wants to be transported — not lectured. Mobile-likely, attention-budget low. The hotspot system is the <strong>single feature</strong> designed for this audience — it turns abstract dots into a place they can stand.</p><p><strong>Primary — space enthusiast / educator.</strong> Knows the Apollo missions by number, knows the rover names, has seen the famous photos. Wants the <strong>comparison</strong> — six Apollo landing sites side-by-side at the same scale, six Mars rovers across 25 years of exploration, the failed Soviet attempts as ghost markers. Wants the fidelity — every detail correct, every photo dated and credited, the regolith at the right brightness.</p><p><strong>Primary — astrodynamicist / scientist.</strong> Comes from /plan or /fly, occasionally checks where a real landing actually happened versus a porkchop target. Cares less about visual fidelity, more about positional accuracy — latitude/longitude must match published coordinates, the orbital-imagery overlay must be georeferenced correctly against the moon-projection / mars-projection mesh.</p><p><strong>Secondary — first-time visitor on landing page.</strong> They never reach a hotspot directly. But the existence of hotspots is the <strong>answer to &quot;what makes Orrery different.&quot;</strong> The landing page (PRD-013) will mention &quot;Visit Tranquillity Base, Mont Mercou, Hadley-Apennine&quot; with three thumbnails that deep-link to those hotspots. This is where the curiosity-to-engagement funnel terminates.</p><p><strong>Out of audience.</strong> Users actively planning real spacecraft missions — they&#39;re not coming to Orrery for landing-site reconnaissance; they use NASA&#39;s Mars Trek / LRO Quickmap / planetary data system directly. We are emphatically <strong>not competing with those tools.</strong> We are bringing 5% of their fidelity to 100% of the lay-audience reach.</p><hr><h2 id="§promises" tabindex="-1">§promises <a class="header-anchor" href="#§promises" aria-label="Permalink to &quot;§promises&quot;">​</a></h2><p>The hotspot system promises seven things:</p><ol><li><strong>Progressive disclosure, not modal interruption.</strong> Zooming is the gesture that reveals more detail. The user is never forced through a dialog or a &quot;click here to see more.&quot; The camera flies in, the model swells, the texture sharpens, the panorama unfurls — all on a single continuous wheel/pinch.</li><li><strong>Photo-realistic at the close tier.</strong> When a hotspot reaches Tier 2 it shows the <strong>real LROC or HiRISE orbital mosaic</strong> of that specific landing site, georeferenced to within 50 m of published coordinates. Tier 3 shows the <strong>actual NASA panorama photographs</strong> from the actual mission. Nothing illustrative; nothing speculative; nothing &quot;artist&#39;s impression.&quot;</li><li><strong>Engineering-correct 3D models.</strong> Each landing-site model is hand-authored from public engineering drawings — Apollo LM descent + ascent stage proportions per NASA TN D-7700, Curiosity wheelbase per JPL drawings, Viking tripod-leg geometry per LARC reports. No artist-license; every dimension citable.</li><li><strong>Full provenance.</strong> Every orbital texture, every panorama, every 3D model carries a row in <code>image-provenance.json</code> / <code>text-sources.json</code> per ADR-046. License + agency + Commons-or-equivalent URL + date. The Credits page shows them all. A new license category — &quot;georeferenced orbital mosaic&quot; — is added.</li><li><strong>Mobile parity.</strong> Every tier renders on a 375 px viewport at 30 fps minimum on a mid-range Android. Asset budgets are mobile-first; the desktop just gets unused headroom.</li><li><strong>All 14 supported locales.</strong> Every annotation label, every panorama caption, every &quot;Visit landing site&quot; CTA goes through Paraglide. 13 sites × 14 locales = 182 overlay strings minimum (estimate: ~6 strings per site → ~1,100 total).</li><li><strong>No degradation of the existing experience.</strong> Today&#39;s /moon and /mars pages work. The hotspot system is <strong>additive</strong> — Tier 0 is what we have today, Tier 1+ unlocks progressively. A user who never zooms past the wide view sees no change. Performance, accessibility, mobile, and i18n behaviour at Tier 0 are protected.</li></ol><hr><h2 id="§scope" tabindex="-1">§scope <a class="header-anchor" href="#§scope" aria-label="Permalink to &quot;§scope&quot;">​</a></h2><h3 id="in-scope-v1-—-the-seven-iconic-sites" tabindex="-1">In scope (V1 — &quot;the seven iconic sites&quot;) <a class="header-anchor" href="#in-scope-v1-—-the-seven-iconic-sites" aria-label="Permalink to &quot;In scope (V1 — &quot;the seven iconic sites&quot;)&quot;">​</a></h3><p><strong>Moon hotspots, full Tier 0–2:</strong></p><ul><li>Apollo 11 (Tranquillity Base) — the canonical demo site.</li><li>Apollo 17 (Taurus-Littrow) — last crewed lunar mission, deepest exploration.</li><li>Chang&#39;e 5 (Mons Rümker) — most recent sample return.</li><li>Luna 9 (Oceanus Procellarum) — first soft landing on any celestial body, 1966.</li></ul><p><strong>Mars hotspots, full Tier 0–2:</strong></p><ul><li>Curiosity (Gale Crater) — longest-running active surface mission.</li><li>Perseverance (Jezero Crater) — most recent rover, most ambitious mission.</li><li>Viking 1 (Chryse Planitia) — first US Mars landing, 1976.</li></ul><p><strong>For each V1 site:</strong></p><ul><li>A hand-authored 3D model of the lander/rover (Tier 1).</li><li>A circular orbital-imagery patch (1 km × 1 km on the surface, 2048×2048 px JPEG from LROC NAC / HiRISE), Tier 2.</li><li>3–6 ground-level annotation markers within the patch (LM, US flag, Solar Wind Composition, MESA, descent-engine scorch).</li><li>Provenance rows for the patch + model + annotations.</li></ul><p><strong>Tier transitions</strong> drive on camera distance to the surface point. Smooth fade-in via <code>THREE.LOD</code> (or equivalent manual dispatcher per RFC-017). Both /moon and /mars get a &quot;Visit landing site&quot; button in the existing detail panel that animates the camera into the Tier 2 close-up; user can wheel out at any time.</p><p><strong>Per-route layer chip.</strong> Both /moon and /mars get a new chip in the existing hud-controls strip: <code>HOTSPOT QUALITY · AUTO / LOW / HIGH</code>. AUTO is the default progressive system. LOW pins Tier 0 (today&#39;s behaviour, for low-power devices). HIGH forces Tier 2 on the selected marker regardless of camera distance.</p><p><strong>Build-pipeline integration.</strong> New <code>scripts/fetch-hotspot-imagery.ts</code> downloads + crops + JPEG-encodes the orbital mosaic per V1 hotspot. New <code>static/data/hotspots/{moon|mars}/{id}.json</code> carries the manifest (centre lat/lon, patch radius, annotation list, model id, source URLs). <code>scripts/build-image-provenance.ts</code> extends to register the new asset family.</p><p><strong>Smoke + e2e.</strong> Per-hotspot Playwright test: click the marker, click Visit, assert canvas is no longer at far-zoom, assert annotations are rendered, assert canvas pixels at the patch centre are non-uniform (the LROC mosaic vs. solid-color regolith texture). Mobile + desktop variants. Console-error-free.</p><h3 id="out-of-scope-v1" tabindex="-1">Out of scope (V1) <a class="header-anchor" href="#out-of-scope-v1" aria-label="Permalink to &quot;Out of scope (V1)&quot;">​</a></h3><ul><li>Ground-view skybox / panorama mode (Tier 3) — this is V2. Walking around inside the LM. Looking around at Mont Mercou. Whole separate UX shell with its own controls and audio. <strong>Promised</strong>, not in V1.</li><li>Tracking video — Perseverance has hours of Ingenuity flight video and rover-traverse video. A &quot;watch the rover drive&quot; UI is V3.</li><li>/earth + /iss + /tiangong hotspots — we&#39;d add ISS module-by-module zoom (V2 reach), DSN station hotspots (Goldstone / Madrid / Canberra) on /earth (V3 reach). Out for V1.</li><li>Mid-zoom auto-rotation, fly-around — the camera goes in once and out once. No orbital flythrough animation. V2 idea.</li><li>Audio — astronaut voice clips at sites are an obvious next move (Apollo 11 &quot;the Eagle has landed&quot;, Apollo 17 &quot;we leave as we came&quot;). Royalty + provenance discipline + multilingual subtitle review = its own ADR. V2.</li><li>VR / WebXR — the panorama framework in V2 is <strong>stereoscopy-ready</strong>. Actual VR mode (controllers, room-scale) is v0.9+.</li></ul><h3 id="v2-—-the-immersive-promise" tabindex="-1">V2 — &quot;the immersive promise&quot; <a class="header-anchor" href="#v2-—-the-immersive-promise" aria-label="Permalink to &quot;V2 — &quot;the immersive promise&quot;&quot;">​</a></h3><p>Tier 3 (ground-view) for the seven V1 sites: NASA panoramas as skybox. User clicks <code>Visit</code> → existing camera animates down; new <code>Stand at site</code> chip appears → second camera transition to ground level + panorama loads. ESC or <code>Return to orbit</code> flies back up. Single panorama per site for V1.5 (the canonical &quot;where they planted the flag&quot; view); multiple panorama waypoints (Apollo 17 has 50+) is V2.5.</p><h3 id="v3-—-the-full-inventory" tabindex="-1">V3 — &quot;the full inventory&quot; <a class="header-anchor" href="#v3-—-the-full-inventory" aria-label="Permalink to &quot;V3 — &quot;the full inventory&quot;&quot;">​</a></h3><p>All 12+ moon sites, all 12+ Mars sites at Tier 2. Failed landings as ghost hotspots (Beagle 2, Schiaparelli, Mars Polar Lander — coordinate-best-estimate + &quot;site unconfirmed&quot; provenance row). ISS modules at module-by-module zoom on /iss (Tier 2 = climb into Cupola, see the actual ISS-mounted cameras&#39; image-of-the-day stream as a skybox). DSN station hotspots on /earth.</p><h3 id="v4-—-the-network-of-operators" tabindex="-1">V4 — &quot;the network of operators&quot; <a class="header-anchor" href="#v4-—-the-network-of-operators" aria-label="Permalink to &quot;V4 — &quot;the network of operators&quot;&quot;">​</a></h3><p>JAXA, ESA, ISRO, CNSA, Roscosmos partner imagery. Chang&#39;e Yutu rover ground panoramas. ISRO Chandrayaan-3 site (the IMAGE-OF-AMBIGUITY moment — the lander is at the south pole; HiRISE has imaged it). India + China + Russia open imagery. Same provenance discipline; new agencies in <code>defaultLicenseForAgency</code> per ADR-046.</p><hr><h2 id="§non-goals-locked" tabindex="-1">§non-goals (locked) <a class="header-anchor" href="#§non-goals-locked" aria-label="Permalink to &quot;§non-goals (locked)&quot;">​</a></h2><p>We commit to these constraints:</p><ol><li><strong>No content we can&#39;t attribute.</strong> If a photograph doesn&#39;t have a clear NASA / ESA / JAXA / CNSA / Roscosmos / ISRO / Commons URL with a public-domain or compatible licence, it does not ship. Even if it would look great.</li><li><strong>No artist&#39;s-impression imagery.</strong> &quot;Mars surface&quot; backdrops painted by an artist or AI do not ship at any tier. Tier 2 = real orbital mosaic; Tier 3 = real panorama. Period.</li><li><strong>No telemetry, no accounts, no backend.</strong> Hotspot system is fully static. All assets ship in the gh-pages bundle (or are lazy-loaded from gh-pages). No &quot;log in to unlock.&quot; No analytics on which hotspots get visited.</li><li><strong>No promotional language.</strong> No &quot;Experience the Moon in unprecedented detail.&quot; Engineering-blueprint tone, same as /science. Marketing copy goes in the landing-page intro (PRD-013), not in feature UI.</li><li><strong>No false fidelity claims.</strong> When Tier 2 georegistration drifts beyond 50 m of published coordinates (which it will for some sites whose orbital imagery is older / less calibrated), we surface the uncertainty in the panel (&quot;HiRISE mosaic registered ±150 m&quot;). Honest provenance is design.</li><li><strong>No content geo-restricted by IP.</strong> Every hotspot is reachable from every country we can serve gh-pages to. No &quot;this content not available in your region.&quot;</li></ol><hr><h2 id="§ux-detail-—-what-each-tier-looks-like" tabindex="-1">§UX detail — what each tier looks like <a class="header-anchor" href="#§ux-detail-—-what-each-tier-looks-like" aria-label="Permalink to &quot;§UX detail — what each tier looks like&quot;">​</a></h2><h3 id="tier-0-—-wide-orbit-view-today-s-behaviour" tabindex="-1">Tier 0 — wide-orbit view (today&#39;s behaviour) <a class="header-anchor" href="#tier-0-—-wide-orbit-view-today-s-behaviour" aria-label="Permalink to &quot;Tier 0 — wide-orbit view (today&#39;s behaviour)&quot;">​</a></h3><p>Camera 4–25× planet-radius away. Marker = small low-poly silhouette (the existing /earth-quality pin pattern proposed in #121). Label leader line floats outward. Hover tooltip = site name. Click = opens detail panel as today. <strong>Nothing changes.</strong></p><h3 id="tier-1-—-mid-zoom-camera-1-5–4×-planet-radius-away" tabindex="-1">Tier 1 — mid-zoom (camera 1.5–4× planet-radius away) <a class="header-anchor" href="#tier-1-—-mid-zoom-camera-1-5–4×-planet-radius-away" aria-label="Permalink to &quot;Tier 1 — mid-zoom (camera 1.5–4× planet-radius away)&quot;">​</a></h3><p>Marker swaps to a detailed 3D model:</p><ul><li>Apollo 11 LM at correct 7 m height: descent stage + ascent stage + 4 splayed legs + ladder + RTG + S-band antenna + foil texture.</li><li>Curiosity rover at 3 m length: chassis + 6 wheels + RTG + camera mast + ChemCam laser + robotic arm + tracks behind it.</li><li>Viking 1 lander: tripod legs + meteorology boom + S-band high-gain dish + sample arm.</li></ul><p>Model is shaded by the route&#39;s lighting (sun-position-correct, ADR-058 cislunar work informs the lighting model on /moon). Label scales smoothly via the existing camera-distance scaling pattern. Halo overlay (#119) renders behind, not in front. No texture swap on the surface yet — Mars stays Mars, Moon stays Moon.</p><h3 id="tier-2-—-close-zoom-camera-0-05–1-5×-planet-radius-away" tabindex="-1">Tier 2 — close-zoom (camera 0.05–1.5× planet-radius away) <a class="header-anchor" href="#tier-2-—-close-zoom-camera-0-05–1-5×-planet-radius-away" aria-label="Permalink to &quot;Tier 2 — close-zoom (camera 0.05–1.5× planet-radius away)&quot;">​</a></h3><p>Camera is now <strong>inside</strong> the planet-radius — the user has flown in. Three things happen simultaneously over a 600 ms transition:</p><ol><li><strong>Surface texture swaps locally.</strong> A 1 km × 1 km circular patch of the actual orbital mosaic (LROC NAC for Moon, HiRISE for Mars) fades in over the planet&#39;s base texture. The patch is alpha-feathered at the edges so the boundary is invisible. Georegistered to the site&#39;s lat/lon ±50 m.</li><li><strong>3D model swells.</strong> From Tier 1&#39;s ~5-px-on-screen scale to ~50-px scale. Same model — no LOD-2 swap unless authoring effort permits. Camera framing makes the model legible.</li><li><strong>Annotation markers appear.</strong> Per-site list of ~3–6 named features. Apollo 11: <code>LM Descent Stage</code>, <code>Buzz Aldrin (selfie position)</code>, <code>US Flag</code>, <code>Solar Wind Composition Experiment</code>, <code>Passive Seismic Experiment</code>, <code>Tranquillity Base plaque</code>. Each is a small camera-facing sprite with a label, anchored to its real position relative to the LM (within ~5 m). Click an annotation → opens a small popover with one-sentence description + the gallery image showing it.</li></ol><p>User can wheel back out at any time; transitions reverse smoothly.</p><h3 id="tier-3-—-ground-view-v2-not-in-v1" tabindex="-1">Tier 3 — ground-view (V2, not in V1) <a class="header-anchor" href="#tier-3-—-ground-view-v2-not-in-v1" aria-label="Permalink to &quot;Tier 3 — ground-view (V2, not in V1)&quot;">​</a></h3><p>Click &quot;Visit landing site&quot; → camera transitions over 1.2 s from Tier 2 down to ground level, ~5 m from the lander. Skybox replaces the wide-zoom starfield: it&#39;s the actual Apollo 11 <em>Buzz beside the flag, Earth visible, Eagle in background</em> panorama, projected as equirectangular onto a 1000-m radius sphere centred on the user&#39;s eye. The 3D model of the LM remains rendered — slightly transparent or occluded by the panorama background, depending on the panorama&#39;s natural composition.</p><p>User can:</p><ul><li>Click-drag to look around 360°.</li><li>ESC to return to Tier 2 (camera flies back up).</li><li>Tap an annotation that&#39;s visible in the panorama (the flag pole, the descent stage) for the same popover treatment.</li><li>Tap &quot;next panorama&quot; if the site has multiple (Apollo 17&#39;s 50+ EVA station panoramas are out-of-scope for V2 — that&#39;s V2.5).</li></ul><p>The skybox panorama is loaded <strong>lazily</strong> — only after the Tier 2 hotspot has been visited at least once in the session, the panorama prefetch kicks off. The user typically waits 1–3 s for the panorama to land; a small &quot;loading panorama…&quot; toast keeps them oriented. Mobile cellular networks: a <code>data-saver: on</code> check (when <code>connection.saveData</code> is true) suppresses the prefetch — user gets a &quot;tap to load&quot; affordance.</p><hr><h2 id="§content-tiers-and-which-landings-get-which-treatment" tabindex="-1">§content tiers and which landings get which treatment <a class="header-anchor" href="#§content-tiers-and-which-landings-get-which-treatment" aria-label="Permalink to &quot;§content tiers and which landings get which treatment&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tier of treatment</th><th>Treatment</th><th>Sites</th></tr></thead><tbody><tr><td>Showcase</td><td>Full Tier 0–3, hand-authored model, 1 km LROC/HiRISE patch, 4–6 annotations, 1+ ground panorama</td><td>Apollo 11, Apollo 17, Curiosity, Perseverance, Viking 1</td></tr><tr><td>Standard</td><td>Full Tier 0–2 only (no V2 panorama)</td><td>Apollo 12, 14, 15, 16, Chang&#39;e 5, Luna 9, Phoenix, InSight, Mars 3, Chandrayaan-3</td></tr><tr><td>Marker only</td><td>Tier 0 with hand-authored model (#121), no orbital patch</td><td>Failed landings, recent / pending / Soviet sites with sparse imagery</td></tr><tr><td>Fallback (V1 default)</td><td>Tier 0 with generic silhouette (today&#39;s behaviour)</td><td>Everything not in the above tiers</td></tr></tbody></table><p>V1 ships <strong>Showcase × 5 + Standard × 7</strong> (12 total hotspots upgraded). V2 ships <strong>Showcase × 12 + Standard × 18</strong>. V3 ships <strong>everything</strong>.</p><hr><h2 id="§accessibility-·-mobile-·-i18n-·-performance" tabindex="-1">§accessibility · mobile · i18n · performance <a class="header-anchor" href="#§accessibility-·-mobile-·-i18n-·-performance" aria-label="Permalink to &quot;§accessibility · mobile · i18n · performance&quot;">​</a></h2><p><strong>Accessibility.</strong> Every hotspot is reachable by keyboard. The detail panel&#39;s &quot;Visit landing site&quot; button is tabbable. Camera animation respects <code>prefers-reduced-motion</code> — if set, the camera does <strong>not</strong> animate; the view jumps directly to the destination tier. Annotations are aria-labelled. Ground-view panorama has a &quot;describe current view&quot; hidden-text affordance for screen readers (e.g., &quot;You are standing at Tranquillity Base. The lunar module Eagle is 5 metres ahead. Earth is visible in the upper left of the sky.&quot;). The describe-text goes through Paraglide.</p><p><strong>Mobile.</strong> All assets sized for ≤ 4 MB per hotspot patch (2048×2048 JPEG ~3–4 MB at quality 80). Tier-2 patch lazy-loaded on first approach (≥ 0.5× planet-radius camera distance). Tier-3 panorama lazy-loaded on <code>Visit</code> click. <code>connection.saveData</code> and <code>connection.effectiveType === &#39;2g&#39;</code> both suppress eager prefetch. Touch gestures: pinch = zoom (Tier transitions happen mid-pinch); two-finger drag = pan (ground view).</p><p><strong>i18n.</strong> Per-site overlay schema: <code>name</code>, <code>tagline</code>, <code>tier3_describe</code>, plus <code>annotations[].name</code> and <code>annotations[].body</code>. 7 V1 sites × ~7 strings = ~50 strings per locale. argos covers 12 locales; sr-Cyrl manual; es manual via the existing wave-23 toolchain. Same pattern as /fleet space-suit batch — locked in by RFC-017.</p><p><strong>Performance budget.</strong> Tier 0 today is ~200 KB total scene mass. Tier 1 adds ~5 KB per hand-authored model × 12 hotspots = ~60 KB scene-resident. Tier 2 patches are ~3 MB each, <strong>lazy-loaded</strong> (not in scene mass). Tier 3 panoramas are ~5–8 MB each, lazy-loaded on demand. <strong>No prefetch on mobile saveData.</strong> Service worker caches everything once fetched (per existing ADR-016).</p><hr><h2 id="§metrics" tabindex="-1">§metrics <a class="header-anchor" href="#§metrics" aria-label="Permalink to &quot;§metrics&quot;">​</a></h2><p>V1 success looks like:</p><ul><li><strong>All 12 V1 hotspots render Tier 2 cleanly</strong> on a Pixel 6 (mid-range Android) at 30 fps minimum during the transition.</li><li><strong>Provenance manifest grows by ~36 entries</strong> (12 patches + 12 models + 12 annotation-strip aggregates).</li><li><strong>e2e smoke for each hotspot</strong> passes: dot exists at Tier 0, model renders at Tier 1, patch renders at Tier 2, transitions return cleanly.</li><li><strong>i18n parity 13/13 locales</strong> day one for the V1 sites&#39; strings.</li><li><strong>No regression</strong> on /moon or /mars Tier 0 rendering speed (measured by existing perf marks).</li><li><strong>Zero new dependencies.</strong> Three.js LOD + existing texture pipeline. No glTF loader. No new image format.</li></ul><p>V2 success adds:</p><ul><li><strong>Ground-view panorama loads in under 3 s</strong> on a typical 25 Mbps connection (mobile 4G typical) for all five Showcase sites.</li><li><strong>Tap-to-load fallback</strong> kicks in for <code>saveData: true</code> and never preloads.</li><li><strong>Cross-locale describe-text</strong> reviewed for each Showcase site in at least the 4 hand-reviewed locales (en-US, es, sr-Cyrl, ja).</li></ul><p>V3 success is qualitative — &quot;every landing on the public record reachable in 30 seconds from the homepage&quot; — and is a v1.0 readiness criterion.</p><hr><h2 id="§risks-open-items" tabindex="-1">§risks + open items <a class="header-anchor" href="#§risks-open-items" aria-label="Permalink to &quot;§risks + open items&quot;">​</a></h2><ol><li><strong>LROC NAC mosaic licensing.</strong> The mosaics live in the Planetary Data System (PDS); NASA public-domain status is unambiguous for the imagery, but the <em>processed mosaic products</em> may have a co-author (e.g., Arizona State University LROC team). RFC-017 / ADR-060 handle the per-product attribution. Best-case: existing PD-NASA category applies; worst-case: new category <code>PD-ASU-LROC</code> with rationale + verified URL.</li><li><strong>HiRISE georegistration drift.</strong> HiRISE images are calibrated to ±5 m on flat ground, ±50 m on slopes; the published rover-track imagery for Curiosity and Perseverance is georeferenced by JPL to the rover&#39;s own location estimate, which itself has 30 m uncertainty pre-cap. Aggregate ±100 m in worst case. We commit to the <strong>public</strong> number and surface uncertainty.</li><li><strong>Asset-budget enforcement.</strong> A 3–4 MB lazy texture per hotspot is mobile-comfortable, but if 12 V1 hotspots are visited in a single session that&#39;s ~40 MB of texture memory. Three.js doesn&#39;t auto-evict. Manual eviction policy (LRU based on visit order) lives in RFC-017 / ADR-059.</li><li><strong>Apollo 17 panorama selection.</strong> Cernan &amp; Schmitt shot 50+ panoramas across 3 EVAs. V1.5 ships one. Which one? Likely the EVA-3 &quot;South Massif and the LRV&quot; panorama — most cinematic, Earth visible, clear LM in frame. ADR-061 picks per-site.</li><li><strong>WebGL feature support.</strong> Tier 2 patches use anisotropic-filtered textures (sharpness when viewed at glancing angle). Some Android browsers don&#39;t expose anisotropic &gt; 4×. Fallback: mipmap-only, accept slight blur. No new shader code.</li><li><strong>The &quot;uncanny valley&quot; of mid-fidelity 3D models.</strong> A hand-authored Apollo LM at 200 polygons looks great at Tier 1 size. The same model at Tier 2 size starts to look toy-ish. Mitigation: Tier 2 framing zooms in on the <strong>terrain</strong> (where the high-res mosaic carries the visual interest); the model is supporting cast, not hero. Cinema-style — we never linger on the toy-poly.</li><li><strong>Hand-authoring volume.</strong> 12 V1 hotspots × ~3 hours per model = ~36 person-hours. Plus 12 patch authoring + provenance = ~12 person-hours. Plus i18n × ~50 strings × 14 locales = 1 day for argos + manual review. <strong>Realistic V1 build: 2 person-weeks</strong>, plus a week of polish + smoke. The work is mostly Marko-supervised model authoring per the existing pattern.</li><li><strong>Risk of feature creep.</strong> &quot;Stand at site&quot; leads naturally to &quot;drive the rover,&quot; &quot;watch the rover drive,&quot; &quot;see what the rover sees.&quot; Each is a different feature with its own ADR. The PRD commits to the <strong>hotspot-tier transition</strong> as the V1 promise — not &quot;make Orrery a flight simulator.&quot;</li></ol><hr><h2 id="§provenance-budget" tabindex="-1">§provenance budget <a class="header-anchor" href="#§provenance-budget" aria-label="Permalink to &quot;§provenance budget&quot;">​</a></h2><p>This feature alone will roughly <strong>double the imagery footprint</strong> of the project:</p><table tabindex="0"><thead><tr><th>Asset class</th><th>Per hotspot</th><th>× V1 (12)</th><th>× V2 (30)</th><th>× V3 (60+)</th></tr></thead><tbody><tr><td>Orbital-mosaic patch</td><td>3–4 MB</td><td>36–48 MB</td><td>90–120 MB</td><td>180–240 MB</td></tr><tr><td>Ground panorama (V2+)</td><td>5–8 MB</td><td>—</td><td>60–96 MB (5 only)</td><td>300–480 MB</td></tr><tr><td>3D model code</td><td>~5 KB</td><td>60 KB</td><td>150 KB</td><td>300 KB</td></tr></tbody></table><p>The orbital-mosaic patches alone fit under gh-pages&#39; 100 GB-month transfer cap with comfortable margin. The panoramas at V3 reach (60 sites × 8 MB) push toward 500 MB total which still ships fine but warrants CDN consideration. ADR-060 picks a delivery strategy.</p><p>Every asset gets a row in <code>image-provenance.json</code>. The existing fail-closed validator catches anything unattributed at build time. <strong>No exceptions</strong>, including for &quot;obviously&quot; public-domain NASA imagery — every row is filled.</p><hr><h2 id="§what-success-feels-like" tabindex="-1">§what success feels like <a class="header-anchor" href="#§what-success-feels-like" aria-label="Permalink to &quot;§what success feels like&quot;">​</a></h2><p>A 12-year-old in São Paulo opens Orrery on her mom&#39;s phone, taps <code>MOON</code>, sees the lunar disc. She taps a small pin that says <code>Apollo 11</code>. The pin enlarges into a tiny silver pyramid with legs. She pinches in. The pyramid swells into a recognisable spacecraft. Two more pinches and the moon under it has become photographs — actual photographs — of grey rock. Small labels float around the spacecraft: <code>Buzz Aldrin (1969)</code>, <code>American flag</code>, <code>Solar Wind</code>, <code>Where Eagle landed</code>. She taps <code>Visit landing site</code>. The camera drops. Now she is standing on the Moon. The lunar module is in front of her. The sky is black. Above the horizon, half-lit, hangs Earth. She turns her phone. Boulders. Footprints. A discarded boot-cover. Tranquillity Base. She has never been outside Brazil.</p><p>The Portuguese caption at the bottom of the screen reads: <em>&quot;Tranquillity Base · 20 de julho de 1969. Você está vendo o ponto exato onde a Apollo 11 pousou.&quot;</em></p><p>She screenshots it, sends it to her dad.</p><p>That&#39;s V1.</p><hr><p><em>PRD-014 · v0.1 draft · May 2026 · Marko Dragoljevic</em></p>',98)])])}const m=t(i,[["render",s]]);export{u as __pageData,m as default};
